#ifndef RMSNORM_H128_KERNEL_H_
#define RMSNORM_H128_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>

#ifndef HIDDEN_SIZE
#define HIDDEN_SIZE 128
#endif

#ifndef RMS_EPS
#define RMS_EPS 1e-6f
#endif

// CUDA launcher for rmsnorm hidden_size=128
void rmsnorm_h128_launcher(const __nv_bfloat16* __restrict__ hidden_states,
                           const __nv_bfloat16* __restrict__ weight,
                           __nv_bfloat16* __restrict__ output,
                           int batch_size,
                           cudaStream_t stream);

// PyTorch entry point
torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight);

#endif // RMSNORM_H128_KERNEL_H_

#include "kernel.h"
#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#ifndef WARP_SIZE
#define WARP_SIZE 32
#endif

// Error checking macro
#ifndef CUDA_CHECK
#define CUDA_CHECK(call)                                                        \
  do {                                                                          \
    cudaError_t _e = (call);                                                    \
    if (_e != cudaSuccess) {                                                    \
      printf("CUDA Error %s at %s:%d\n", cudaGetErrorString(_e), __FILE__,      \
             __LINE__);                                                         \
    }                                                                           \
  } while (0)
#endif

static __device__ __forceinline__ float bf16_to_float(const __nv_bfloat16 x) {
  return __bfloat162float(x);
}

static __device__ __forceinline__ __nv_bfloat16 float_to_bf16(const float x) {
  return __float2bfloat16_rn(x);
}

static __device__ __forceinline__ float warp_reduce_sum(float val) {
#pragma unroll
  for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
    val += __shfl_down_sync(0xffffffff, val, offset);
  }
  return val;
}

template <int HSIZE>
__launch_bounds__(HSIZE, 8)
__global__ void rmsnorm_h128_kernel(const __nv_bfloat16* __restrict__ hidden_states,
                                    const __nv_bfloat16* __restrict__ weight,
                                    __nv_bfloat16* __restrict__ output,
                                    int batch_size) {
  const int row = blockIdx.x;
  if (row >= batch_size) return;

  const int tid = threadIdx.x; // [0, HSIZE-1]
  const int lane = tid & (WARP_SIZE - 1);
  const int warp_id = tid / WARP_SIZE;

  // Each block processes one row of length HSIZE
  const __nv_bfloat16* x_row = hidden_states + row * HSIZE;
  __nv_bfloat16* y_row = output + row * HSIZE;

  // Load input
  float x = bf16_to_float(x_row[tid]);
  float xsq = x * x;

  // Warp-level reduction
  float wsum = warp_reduce_sum(xsq);

  // Shared storage for per-warp sums and inv_rms
  __shared__ float warp_sums[HSIZE / WARP_SIZE];
  __shared__ float inv_rms_val;

  if (lane == 0) {
    warp_sums[warp_id] = wsum;
  }
  __syncthreads();

  // First warp reduces the per-warp sums
  if (tid < WARP_SIZE) {
    float sum = (tid < (HSIZE / WARP_SIZE)) ? warp_sums[tid] : 0.f;
    sum = warp_reduce_sum(sum);

    if (tid == 0) {
      float mean = sum * (1.0f / static_cast<float>(HSIZE));
      float inv_rms = rsqrtf(mean + RMS_EPS);
      inv_rms_val = inv_rms;
    }
  }
  __syncthreads();

  // Load weight and compute y = (x * inv_rms) * weight
  float w = bf16_to_float(weight[tid]);
  float y = x * inv_rms_val * w;

  y_row[tid] = float_to_bf16(y);
}

void rmsnorm_h128_launcher(const __nv_bfloat16* __restrict__ hidden_states,
                           const __nv_bfloat16* __restrict__ weight,
                           __nv_bfloat16* __restrict__ output,
                           int batch_size,
                           cudaStream_t stream) {
  if (batch_size <= 0) {
    return;
  }
  constexpr int HSIZE = HIDDEN_SIZE;
  static_assert(HSIZE == 128, "This launcher is specialized for hidden_size == 128");

  dim3 block(HSIZE, 1, 1);
  dim3 grid(batch_size, 1, 1);

  rmsnorm_h128_kernel<HSIZE><<<grid, block, 0, stream>>>(
      hidden_states, weight, output, batch_size);

  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <limits>
#include "kernel.h"

static inline void check_inputs(const torch::Tensor& hidden_states,
                                const torch::Tensor& weight) {
  TORCH_CHECK(hidden_states.device().is_cuda(), "hidden_states must be a CUDA tensor");
  TORCH_CHECK(weight.device().is_cuda(), "weight must be a CUDA tensor");
  TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16, "hidden_states must be bfloat16 dtype");
  TORCH_CHECK(weight.dtype() == torch::kBFloat16, "weight must be bfloat16 dtype");
  TORCH_CHECK(hidden_states.dim() == 2, "hidden_states must have shape [batch_size, hidden_size]");
  TORCH_CHECK(hidden_states.size(1) == HIDDEN_SIZE,
              "hidden_states second dimension must be ", HIDDEN_SIZE);
  TORCH_CHECK(weight.dim() == 1 && weight.size(0) == HIDDEN_SIZE,
              "weight must have shape [", HIDDEN_SIZE, "]");
  TORCH_CHECK(hidden_states.is_contiguous(), "hidden_states must be contiguous");
  TORCH_CHECK(weight.is_contiguous(), "weight must be contiguous");
  TORCH_CHECK(hidden_states.size(0) >= 0, "batch_size must be non-negative");
  TORCH_CHECK(hidden_states.device() == weight.device(),
              "hidden_states and weight must be on the same CUDA device");
}

torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
  check_inputs(hidden_states, weight);

  const int64_t batch_size64 = hidden_states.size(0);
  TORCH_CHECK(batch_size64 <= static_cast<int64_t>(std::numeric_limits<int>::max()),
              "batch_size too large for int grid size");
  const int batch_size = static_cast<int>(batch_size64);

  auto output = torch::empty_like(hidden_states);

  if (batch_size == 0) {
    return output;
  }

  // Extract raw pointers (reinterpret to __nv_bfloat16)
  const __nv_bfloat16* x_ptr =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<c10::BFloat16>());
  const __nv_bfloat16* w_ptr =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<c10::BFloat16>());
  __nv_bfloat16* y_ptr =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<c10::BFloat16>());

  // Launch kernel on current CUDA stream
  auto stream = at::cuda::getCurrentCUDAStream();
  rmsnorm_h128_launcher(x_ptr, w_ptr, y_ptr, batch_size, stream.stream());

  // Error check after launch
  cudaError_t err = cudaGetLastError();
  TORCH_CHECK(err == cudaSuccess, "CUDA kernel launch failed: ", cudaGetErrorString(err));

  return output;
}

// PyBind registration
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
